#!/usr/bin/env bash
# skymesh-linux-ap.sh — bring up a visible "skymesh" WiFi AP on a Linux node.
#
# This is the phone-visible SSID/BSSID path. It expects a Linux kernel with
# hostapd + iw and a WiFi adapter that supports AP mode. Realtek adapters that
# enumerate as 0bda:1a2b are usually in driver-disk mode; with usb_modeswitch
# present, this script tries the known non-destructive switch message first.
#
# Default mode is dry-run/preflight. Pass --run to start skymesh-wifi-pluto with
# --ap-run-hostapd. The Rust endpoint still refuses Pluto TX unless --enable-tx
# is forwarded separately after RF preflight.
#
# Usage:
#   sudo scripts/skymesh-linux-ap.sh --iface wlan0 --public-host 192.168.69.1 --run

set -eu

IFACE="${SKYMESH_AP_IFACE:-wlan0}"
SSID="${SKYMESH_AP_SSID:-skymesh}"
CHANNEL="${SKYMESH_AP_CHANNEL:-6}"
PUBLIC_HOST="${SKYMESH_PUBLIC_HOST:-192.168.69.1}"
HTTP_BIND="${SKYMESH_HTTP_BIND:-0.0.0.0:8732}"
CONFIG_OUT="${SKYMESH_HOSTAPD_CONFIG:-/tmp/skymesh-hostapd.conf}"
RUN=0
BIN=""
PASSPHRASE=""
ENABLE_TX=0

while [ $# -gt 0 ]; do
  case "$1" in
    --iface|--ap-interface) IFACE="$2"; shift 2 ;;
    --ssid|--ap-ssid) SSID="$2"; shift 2 ;;
    --channel|--ap-channel) CHANNEL="$2"; shift 2 ;;
    --public-host) PUBLIC_HOST="$2"; shift 2 ;;
    --http-bind) HTTP_BIND="$2"; shift 2 ;;
    --config-out|--ap-config-out) CONFIG_OUT="$2"; shift 2 ;;
    --bin) BIN="$2"; shift 2 ;;
    --passphrase|--ap-passphrase) PASSPHRASE="$2"; shift 2 ;;
    --enable-tx) ENABLE_TX=1; shift ;;
    --run) RUN=1; shift ;;
    -h|--help) sed -n '2,24p' "$0" | sed 's/^# *//'; exit 0 ;;
    *) echo "unknown arg: $1" >&2; exit 2 ;;
  esac
done

if [ "$(uname -s)" != "Linux" ]; then
  echo "ERROR: AP mode requires Linux hostapd/iw support (got $(uname -s))." >&2
  exit 3
fi

SCRIPT_DIR="$(cd "$(dirname "$0")" && pwd)"
DI_ROOT="$(cd "$SCRIPT_DIR/.." && pwd)"
if [ -z "$BIN" ]; then
  if [ -x "$DI_ROOT/target/release/skymesh-wifi-pluto" ]; then
    BIN="$DI_ROOT/target/release/skymesh-wifi-pluto"
  else
    BIN="$DI_ROOT/target/debug/skymesh-wifi-pluto"
  fi
fi

need() {
  command -v "$1" >/dev/null 2>&1 || { echo "ERROR: required command missing: $1" >&2; exit 4; }
}

need iw
need hostapd
[ -x "$BIN" ] || { echo "ERROR: skymesh-wifi-pluto binary not found/executable: $BIN" >&2; exit 4; }

if command -v lsusb >/dev/null 2>&1 && lsusb | grep -qi '0bda:1a2b'; then
  echo "skymesh-linux-ap: Realtek 0bda:1a2b is in DISK mode."
  if command -v usb_modeswitch >/dev/null 2>&1; then
    echo "skymesh-linux-ap: attempting usb_modeswitch 0bda:1a2b -> WiFi mode"
    usb_modeswitch -v 0bda -p 1a2b \
      -M 55534243123456780000000000000061b000000ff000000000000000000000000000 \
      || echo "WARN: usb_modeswitch failed; continuing to iw checks" >&2
    sleep 2
  else
    echo "ERROR: usb_modeswitch missing; install it or switch the adapter manually." >&2
    exit 5
  fi
fi

if ! iw dev | grep -q "Interface ${IFACE}$"; then
  echo "ERROR: iw does not show interface ${IFACE}." >&2
  echo "Available iw devices:" >&2
  iw dev >&2 || true
  exit 6
fi

if ! iw list | grep -A30 'Supported interface modes' | grep -q '^[[:space:]]*\* AP$'; then
  echo "ERROR: this WiFi adapter/driver does not advertise AP mode in iw list." >&2
  iw list | sed -n '/Supported interface modes/,+30p' >&2
  exit 7
fi

args=(
  --ap-mode
  --ap-interface "$IFACE"
  --ap-ssid "$SSID"
  --ap-channel "$CHANNEL"
  --ap-config-out "$CONFIG_OUT"
  --http-bind "$HTTP_BIND"
  --public-host "$PUBLIC_HOST"
)
[ -n "$PASSPHRASE" ] && args+=(--ap-passphrase "$PASSPHRASE")
[ "$ENABLE_TX" -eq 1 ] && args+=(--enable-tx)

if [ "$RUN" -eq 0 ]; then
  echo "skymesh-linux-ap: preflight OK. Writing hostapd config only:"
  "$BIN" "${args[@]}" --ap-config-only
  echo "skymesh-linux-ap: config -> $CONFIG_OUT"
  echo "skymesh-linux-ap: run for real with --run"
  exit 0
fi

echo "skymesh-linux-ap: starting visible SSID '$SSID' on $IFACE (channel $CHANNEL)"
exec "$BIN" "${args[@]}" --ap-run-hostapd
